{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://portolan.dev/schema/evidence-graph.schema.json",
  "title": "Portolan Evidence Graph",
  "type": "object",
  "additionalProperties": false,
  "required": ["schema_version", "generated_by", "nodes", "edges"],
  "properties": {
    "schema_version": {
      "type": "string",
      "const": "0.1.0"
    },
    "generated_by": {
      "type": "string",
      "minLength": 1
    },
    "nodes": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/node"
      }
    },
    "edges": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/edge"
      }
    }
  },
  "$defs": {
    "evidence_state": {
      "type": "string",
      "enum": [
        "source-visible",
        "metadata-visible",
        "runtime-visible",
        "claim-only",
        "unknown",
        "cannot_verify"
      ]
    },
    "evidence": {
      "type": "object",
      "additionalProperties": false,
      "required": ["state", "source"],
      "properties": {
        "state": {
          "$ref": "#/$defs/evidence_state"
        },
        "source": {
          "type": "string",
          "minLength": 1
        },
        "observed_at": {
          "type": "string",
          "format": "date-time"
        },
        "reason": {
          "type": "string"
        }
      }
    },
    "node": {
      "type": "object",
      "additionalProperties": false,
      "required": ["id", "kind", "label", "evidence"],
      "properties": {
        "id": {
          "type": "string",
          "minLength": 1
        },
        "kind": {
          "type": "string",
          "enum": ["repository", "service", "package", "runtime", "team", "claim", "unknown"]
        },
        "label": {
          "type": "string",
          "minLength": 1
        },
        "evidence": {
          "$ref": "#/$defs/evidence"
        }
      }
    },
    "edge": {
      "type": "object",
      "additionalProperties": false,
      "required": ["from", "to", "kind", "evidence"],
      "properties": {
        "from": {
          "type": "string",
          "minLength": 1
        },
        "to": {
          "type": "string",
          "minLength": 1
        },
        "kind": {
          "type": "string",
          "enum": ["owns", "depends-on", "exposes", "imports", "observes", "claims", "unknown"]
        },
        "evidence": {
          "$ref": "#/$defs/evidence"
        }
      }
    }
  }
}

package app

import (
	"bytes"
	"strings"
	"testing"
)

func TestRunVersionWritesVersion(t *testing.T) {
	var stdout bytes.Buffer
	var stderr bytes.Buffer

	code := Run([]string{"--version"}, &stdout, &stderr)

	if code != 0 {
		t.Fatalf("Run returned %d, want 0", code)
	}
	if got := strings.TrimSpace(stdout.String()); got != "portolan dev" {
		t.Fatalf("stdout = %q, want %q", got, "portolan dev")
	}
	if stderr.Len() != 0 {
		t.Fatalf("stderr = %q, want empty", stderr.String())
	}
}

func TestRunScanHelpDescribesReadOnlyEvidenceGraph(t *testing.T) {
	var stdout bytes.Buffer
	var stderr bytes.Buffer

	code := Run([]string{"scan", "--help"}, &stdout, &stderr)

	if code != 0 {
		t.Fatalf("Run returned %d, want 0", code)
	}
	out := stdout.String()
	for _, want := range []string{"read-only", "evidence graph", "source-visible", "unknown"} {
		if !strings.Contains(out, want) {
			t.Fatalf("stdout %q does not contain %q", out, want)
		}
	}
	if stderr.Len() != 0 {
		t.Fatalf("stderr = %q, want empty", stderr.String())
	}
}

func TestRunUnknownCommandReturnsUsageError(t *testing.T) {
	var stdout bytes.Buffer
	var stderr bytes.Buffer

	code := Run([]string{"rewrite"}, &stdout, &stderr)

	if code != 2 {
		t.Fatalf("Run returned %d, want 2", code)
	}
	if stdout.Len() != 0 {
		t.Fatalf("stdout = %q, want empty", stdout.String())
	}
	if got := stderr.String(); !strings.Contains(got, "unknown command") {
		t.Fatalf("stderr = %q, want unknown command message", got)
	}
}
